/**
 * Processa e prepara um array de objetos JSON, escapando strings e garantindo campos obrigatórios.
 * 
 * @param {Array} items - O array de itens a serem processados.
 * @returns {Array} - O array de objetos processados com valores escapados e campos obrigatórios.
 */
function processAndEscapeItems(items) {
    // Lista de campos obrigatórios com valores padrão null
    const REQUIRED_FIELDS = [
        "account_id", "actor_id", "instagram_user_id", "instagram_permalink_url",
        "effective_instagram_media_id", "id", "name", "call_to_action_type",
        "object_type", "status", "thumbnail_url", "thumbnail_id", "video_id",
        "body", "title", "image_url"
    ];

    // Função otimizada de escape para strings
    function escapeString(value) {
        if (typeof value !== 'string') return value;

        return value
            .replace(/'/g, "''")
            .replace(/\\/g, "\\\\")
            .replace(/\n/g, "\\n");
    }

    return items.map(item => {
        // Cria uma cópia do objeto para evitar mutação
        const processedItem = { ...item.json };

        // Adiciona campos obrigatórios faltantes
        REQUIRED_FIELDS.forEach(field => {
            if (!(field in processedItem)) {
                processedItem[field] = null;
            }
        });

        // Converte undefined para null e escapa strings
        for (const key in processedItem) {
            processedItem[key] = processedItem[key] === undefined 
                ? null 
                : escapeString(processedItem[key]);
        }

        return processedItem;
    });
}

// Exporta a função para processamento dos itens
return processAndEscapeItems($input.all());

